`,paraId:14,tocIndex:5},{value:"\u6570\u503C\u7684\u5C55\u793A\u548C\u53D8\u66F4\u9700\u8981\u7531",paraId:15,tocIndex:6},{value:"state",paraId:15,tocIndex:6},{value:"\u548C",paraId:15,tocIndex:6},{value:"setState",paraId:15,tocIndex:6},{value:"\uFF0C\u7EC4\u4EF6\u5185\u90E8\u63A7\u5236 state\uFF0C\u5E76\u5B9E\u73B0\u81EA\u5DF1\u7684 onChange \u65B9\u6CD5",paraId:15,tocIndex:6},{value:`//\u7EC4\u4EF6
